import java.io.*;class Main{static int splitArray(int[]a,int k){long lo=0,hi=0;for(int x:a){if(x>lo)lo=x;hi+=x;}while(lo<hi){long mid=(lo+hi)/2,cur=0;int pieces=1;for(int x:a){if(cur+x>mid){pieces++;cur=x;}else cur+=x;}if(pieces<=k)hi=mid;else lo=mid+1;}return(int)lo;}public static void main(String[]args)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]),k=Integer.parseInt(d[idx++]);int[]a=new int[n];for(int i=0;i<n;i++)a[i]=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append(splitArray(a,k));}System.out.print(out);}}
